27	const PROCESSING_FEE = 5;
28	const LOYALTY_DISCOUNT_RATE = 0.2;
29	const LOYALTY_THRESHOLD_YEARS = 2;
30	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
31	const COMPONENT_TYPES = ["rune", "moonstone"];
32	const BLOCK_SIZE = 3;
33	const BLOCK_PREMIUM = 60;
34	const CURSE_SURCHARGE_RATE = 0.5;
35	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
36	const HIGH_ENCHANTMENT_THRESHOLD = 5;
37	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
38	
39	const BASE_PREMIUMS: Record<string, number> = {
40	  sword: 100,
41	  amulet: 60,
42	  staff: 80,
43	  potion: 40,
44	  rune: 25,
45	  moonstone: 25,
46	};
47	
48	const isComponent = (item: Item): boolean =>
49	  COMPONENT_TYPES.includes(item.type);
50	
51	const calculateItemPremium = (item: Item): number => {
52	  const base = BASE_PREMIUMS[item.type] ?? 0;
53	  let premium = base;
54	  if (item.cursed) {
55	    premium += base * CURSE_SURCHARGE_RATE;
56	  }
57	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
58	    premium += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
59	  }
60	  return premium;
61	};
62	
63	const calculateComponentPremium = (
64	  componentCounts: Record<string, number>,
65	): number => {
66	  let total = 0;
67	  for (const [type, count] of Object.entries(componentCounts)) {
68	    total +=
69	      count === BLOCK_SIZE
70	        ? BLOCK_PREMIUM
71	        : count * (BASE_PREMIUMS[type] ?? 0);
72	  }
73	  return total;
74	};
