76	export function processScenario(scenario: Scenario): ScenarioOutput {
77	  let quoteCount = 0;
78	
79	  const results = scenario.steps.map((step) => {
80	    quoteCount++;
81	
82	    const componentCounts: Record<string, number> = {};
83	    let itemTotal = 0;
84	    let rawBaseSum = 0;
85	
86	    for (const item of step.items) {
87	      if (isComponent(item)) {
88	        componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
89	      } else {
90	        itemTotal += calculateItemPremium(item);
91	        rawBaseSum += BASE_PREMIUMS[item.type] ?? 0;
92	      }
93	    }
94	
95	    const componentPremium = calculateComponentPremium(componentCounts);
96	    itemTotal += componentPremium;
97	    rawBaseSum += componentPremium;
98	
99	    const policyBase = rawBaseSum;
100	    let totalBeforeFee = itemTotal;
101	
102	    // Policy-wide modifiers (all percentages of policyBase)
103	    totalBeforeFee += policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
104	
105	    if (scenario.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
106	      totalBeforeFee -= policyBase * LOYALTY_DISCOUNT_RATE;
107	    }
108	
109	    if (quoteCount > 1) {
110	      totalBeforeFee -= policyBase * FOLLOW_UP_DISCOUNT_RATE;
111	    }
112	
113	    const finalPremium = totalBeforeFee + PROCESSING_FEE;
114	    return { premium: Math.ceil(parseFloat(finalPremium.toFixed(10))) };
115	  });
116	  return { results };
117	}
