1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface QuoteStep {
8	  op: "quote";
9	  items: Item[];
10	}
11	
12	interface Damage {
13	  itemType: string;
14	  amount: number;
15	}
16	
17	interface ClaimStep {
18	  op: "claim";
19	  policy: number;
20	  incident: {
21	    cause: string;
22	    damages: Damage[];
23	  };
24	}
25	
26	type Step = QuoteStep | ClaimStep;
27	
28	interface Scenario {
29	  customer: { yearsWithMHPCO: number };
30	  steps: Step[];
31	}
32	
33	interface QuoteResult {
34	  premium: number;
35	}
36	
37	interface ClaimResult {
38	  payout: number;
39	  remainingCap: number;
40	}
41	
42	interface Policy {
43	  items: Item[];
44	  insuranceSum: number;
45	  remainingCap: number;
46	}
47	
48	interface ScenarioOutput {
49	  results: (QuoteResult | ClaimResult)[];
50	}
51	
52	const PROCESSING_FEE = 5;
53	const DEDUCTIBLE = 100;
54	
55	const INSURANCE_VALUES: Record<string, number> = {
56	  sword: 1000,
57	  amulet: 600,
58	  staff: 800,
59	  potion: 400,
60	  rune: 250,
61	  moonstone: 250,
62	};
63	const LOYALTY_DISCOUNT_RATE = 0.2;
64	const LOYALTY_THRESHOLD_YEARS = 2;
65	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
66	const COMPONENT_TYPES = ["rune", "moonstone"];
67	const BLOCK_SIZE = 3;
68	const BLOCK_PREMIUM = 60;
69	const CURSE_SURCHARGE_RATE = 0.5;
70	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
71	const HIGH_ENCHANTMENT_THRESHOLD = 5;
72	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
73	
74	const BASE_PREMIUMS: Record<string, number> = {
75	  sword: 100,
76	  amulet: 60,
77	  staff: 80,
78	  potion: 40,
79	  rune: 25,
80	  moonstone: 25,
81	};
82	
83	const isComponent = (item: Item): boolean =>
84	  COMPONENT_TYPES.includes(item.type);
85	
86	const calculateItemPremium = (item: Item): number => {
87	  const base = BASE_PREMIUMS[item.type] ?? 0;
88	  let premium = base;
89	  if (item.cursed) {
90	    premium += base * CURSE_SURCHARGE_RATE;
91	  }
92	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
93	    premium += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
94	  }
95	  return premium;
96	};
97	
98	const calculateComponentPremium = (
99	  componentCounts: Record<string, number>,
100	): number => {
101	  let total = 0;
102	  for (const [type, count] of Object.entries(componentCounts)) {
103	    total +=
104	      count === BLOCK_SIZE
105	        ? BLOCK_PREMIUM
106	        : count * (BASE_PREMIUMS[type] ?? 0);
107	  }
108	  return total;
109	};
110	
111	export function processScenario(scenario: Scenario): ScenarioOutput {
112	  let quoteCount = 0;
113	  const policies: Map<number, Policy> = new Map();
114	
115	  const results = scenario.steps.map((step, stepIndex) => {
116	    if (step.op === "quote") {
117	      quoteCount++;
118	
119	      const componentCounts: Record<string, number> = {};
120	      let itemTotal = 0;
121	      let rawBaseSum = 0;
122	      let insuranceSum = 0;
123	
124	      for (const item of step.items) {
125	        insuranceSum += INSURANCE_VALUES[item.type] ?? 0;
126	        if (isComponent(item)) {
127	          componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
128	        } else {
129	          itemTotal += calculateItemPremium(item);
130	          rawBaseSum += BASE_PREMIUMS[item.type] ?? 0;
131	        }
132	      }
133	
134	      const componentPremium = calculateComponentPremium(componentCounts);
135	      itemTotal += componentPremium;
136	      rawBaseSum += componentPremium;
137	
138	      const policyBase = rawBaseSum;
139	      let totalBeforeFee = itemTotal;
140	
141	      // Policy-wide modifiers (all percentages of policyBase)
142	      totalBeforeFee += policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
143	
144	      if (scenario.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
145	        totalBeforeFee -= policyBase * LOYALTY_DISCOUNT_RATE;
146	      }
147	
148	      if (quoteCount > 1) {
149	        totalBeforeFee -= policyBase * FOLLOW_UP_DISCOUNT_RATE;
150	      }
151	
152	      const finalPremium = totalBeforeFee + PROCESSING_FEE;
153	
154	      policies.set(stepIndex, {
155	        items: step.items,
156	        insuranceSum,
157	        remainingCap: insuranceSum * 2,
158	      });
159	
160	      return { premium: Math.ceil(parseFloat(finalPremium.toFixed(10))) };
161	    } else {
162	      // claim
163	      const policy = policies.get(step.policy)!;
164	
165	      let totalPayout = 0;
166	      for (const damage of step.incident.damages) {
167	        let reimbursement = damage.amount;
168	        const payout = Math.max(0, reimbursement - DEDUCTIBLE);
169	        totalPayout += payout;
170	      }
171	
172	      totalPayout = Math.min(totalPayout, policy.remainingCap);
173	      totalPayout = Math.floor(parseFloat(totalPayout.toFixed(10)));
174	      policy.remainingCap -= totalPayout;
175	
176	      return { payout: totalPayout, remainingCap: policy.remainingCap };
177	    }
178	  });
179	  return { results };
180	}
