1	interface Item {
2	  type: string;
3	  material?: string;
4	  cursed?: boolean;
5	  enchantment?: number;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Damage {
14	  itemType: string;
15	  amount: number;
16	}
17	
18	interface ClaimStep {
19	  op: "claim";
20	  policy: number;
21	  incident: {
22	    cause: string;
23	    damages: Damage[];
24	  };
25	}
26	
27	type Step = QuoteStep | ClaimStep;
28	
29	interface Scenario {
30	  customer: { yearsWithMHPCO: number };
31	  steps: Step[];
32	}
33	
34	interface QuoteResult {
35	  premium: number;
36	}
37	
38	interface ClaimResult {
39	  payout: number;
40	  remainingCap: number;
41	}
42	
43	interface Policy {
44	  items: Item[];
45	  insuranceSum: number;
46	  remainingCap: number;
47	}
48	
49	interface ScenarioOutput {
50	  results: (QuoteResult | ClaimResult)[];
51	}
52	
53	const PROCESSING_FEE = 5;
54	const DEDUCTIBLE = 100;
55	
56	const INSURANCE_VALUES: Record<string, number> = {
57	  sword: 1000,
58	  amulet: 600,
59	  staff: 800,
60	  potion: 400,
61	  rune: 250,
62	  moonstone: 250,
63	};
64	const LOYALTY_DISCOUNT_RATE = 0.2;
65	const LOYALTY_THRESHOLD_YEARS = 2;
66	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
67	const COMPONENT_TYPES = ["rune", "moonstone"];
68	const BLOCK_SIZE = 3;
69	const BLOCK_PREMIUM = 60;
70	const CURSE_SURCHARGE_RATE = 0.5;
71	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
72	const HIGH_ENCHANTMENT_THRESHOLD = 5;
73	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
74	const CLAIM_HIGH_ENCHANTMENT_THRESHOLD = 8;
75	const CLAIM_HIGH_ENCHANTMENT_RATE = 0.5;
76	
77	const BASE_PREMIUMS: Record<string, number> = {
78	  sword: 100,
79	  amulet: 60,
80	  staff: 80,
81	  potion: 40,
82	  rune: 25,
83	  moonstone: 25,
84	};
85	
86	const isComponent = (item: Item): boolean =>
87	  COMPONENT_TYPES.includes(item.type);
88	
89	const calculateItemPremium = (item: Item): number => {
90	  const base = BASE_PREMIUMS[item.type] ?? 0;
91	  let premium = base;
92	  if (item.cursed) {
93	    premium += base * CURSE_SURCHARGE_RATE;
94	  }
95	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
96	    premium += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
97	  }
98	  return premium;
99	};
100	
101	const calculateComponentPremium = (
102	  componentCounts: Record<string, number>,
103	): number => {
104	  let total = 0;
105	  for (const [type, count] of Object.entries(componentCounts)) {
106	    total +=
107	      count === BLOCK_SIZE
108	        ? BLOCK_PREMIUM
109	        : count * (BASE_PREMIUMS[type] ?? 0);
110	  }
111	  return total;
112	};
113	
114	export function processScenario(scenario: Scenario): ScenarioOutput {
115	  let quoteCount = 0;
116	  const policies: Map<number, Policy> = new Map();
117	
118	  const results = scenario.steps.map((step, stepIndex) => {
119	    if (step.op === "quote") {
120	      quoteCount++;
121	
122	      const componentCounts: Record<string, number> = {};
123	      let itemTotal = 0;
124	      let policyBase = 0;
125	      let insuranceSum = 0;
126	
127	      for (const item of step.items) {
128	        insuranceSum += INSURANCE_VALUES[item.type] ?? 0;
129	        if (isComponent(item)) {
130	          componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
131	        } else {
132	          itemTotal += calculateItemPremium(item);
133	          policyBase += BASE_PREMIUMS[item.type] ?? 0;
134	        }
135	      }
136	
137	      const componentPremium = calculateComponentPremium(componentCounts);
138	      itemTotal += componentPremium;
139	      policyBase += componentPremium;
140	
141	      let totalBeforeFee = itemTotal;
142	
143	      // Policy-wide modifiers (all percentages of policyBase)
144	      totalBeforeFee += policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
145	
146	      if (scenario.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
147	        totalBeforeFee -= policyBase * LOYALTY_DISCOUNT_RATE;
148	      }
149	
150	      if (quoteCount > 1) {
151	        totalBeforeFee -= policyBase * FOLLOW_UP_DISCOUNT_RATE;
152	      }
153	
154	      const finalPremium = totalBeforeFee + PROCESSING_FEE;
155	
156	      policies.set(stepIndex, {
157	        items: step.items,
158	        insuranceSum,
159	        remainingCap: insuranceSum * 2,
160	      });
161	
162	      return { premium: Math.ceil(parseFloat(finalPremium.toFixed(10))) };
163	    } else {
164	      // claim
165	      const policy = policies.get(step.policy)!;
166	
167	      let totalPayout = 0;
168	      for (const damage of step.incident.damages) {
169	        let reimbursement = damage.amount;
170	        const payout = Math.max(0, reimbursement - DEDUCTIBLE);
171	        totalPayout += payout;
172	      }
173	
174	      totalPayout = Math.min(totalPayout, policy.remainingCap);
175	      totalPayout = Math.floor(parseFloat(totalPayout.toFixed(10)));
176	      policy.remainingCap -= totalPayout;
177	
178	      return { payout: totalPayout, remainingCap: policy.remainingCap };
179	    }
180	  });
181	  return { results };
182	}
